                              i++; // tăng i lên một đoen vị
                              swap(&arr[i], &arr[j]); // đổi chỗ arr[i] cho arr[j]
                       }
               }
               swap(&arr[i + 1], &arr[h]); //đổi chỗ cho arr[i+1] và arr[h]
